@app.route('/login')
def login():
    """Initiate the OIDC authorization code flow."""
    try:
        provider_config = get_provider_config()
    except Exception as e:
        return jsonify({'error': f'Failed to fetch OIDC provider configuration: {str(e)}'}), 500
    
    # Generate state and nonce for security
    state = secrets.token_urlsafe(32)
    nonce = secrets.token_urlsafe(32)
    
    # Store state and nonce in session for validation
    session['oidc_state'] = state
    session['oidc_nonce'] = nonce
    
    # Build the authorization URL
    auth_params = {
        'response_type': 'code',
        'client_id': OIDC_CONFIG['client_id'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'scope': OIDC_CONFIG['scope'],
        'state': state,
        'nonce': nonce,
    }
    
    authorization_url = f"{provider_config['authorization_endpoint']}?{urlencode(auth_params)}"
    
    return redirect(authorization_url)


@app.route('/callback')
def callback():
    """Handle the OIDC callback after user authentication."""
    # Check for errors from the provider
    error = request.args.get('error')
    if error:
        error_description = request.args.get('error_description', 'Unknown error')
        return jsonify({
            'error': error,
            'error_description': error_description
        }), 400
    
    # Validate state parameter
    state = request.args.get('state')
    stored_state = session.pop('oidc_state', None)
    
    if state is None or state != stored_state:
        return jsonify({'error': 'Invalid state parameter. Possible CSRF attack.'}), 403
    
    # Get the authorization code
    code = request.args.get('code')
    if code is None:
        return jsonify({'error': 'No authorization code received'}), 400
    
    # Get the stored nonce
    nonce = session.pop('oidc_nonce', None)
    
    try:
        provider_config = get_provider_config()
    except Exception as e:
        return jsonify({'error': f'Failed to fetch provider configuration: {str(e)}'}), 500
    
    # Exchange the authorization code for tokens
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'client_id': OIDC_CONFIG['client_id'],
        'client_secret': OIDC_CONFIG['client_secret'],
    }
    
    try:
        token_response = requests.post(
            provider_config['token_endpoint'],
            data=token_data,
            headers={'Content-Type': 'application/x-www-form-urlencoded'},
            timeout=10
        )
        token_response.raise_for_status()
        tokens = token_response.json()
    except requests.exceptions.RequestException as e:
        return jsonify({'error': f'Token exchange failed: {str(e)}'}), 500
    
    # Extract tokens
    id_token = tokens.get('id_token')
    access_token = tokens.get('access_token')
    refresh_token = tokens.get('refresh_token')
    
    if id_token is None:
        return jsonify({'error': 'No ID token received from provider'}), 500
    
    # Decode and validate the ID token
    try:
        claims = decode_id_token(id_token, nonce=nonce)
    except JWTError as e:
        return jsonify({'error': f'ID token validation failed: {str(e)}'}), 401
    except Exception as e:
        return jsonify({'error': f'Failed to decode ID token: {str(e)}'}), 500
    
    # Optionally fetch additional user info from the userinfo endpoint
    user_info = dict(claims)
    
    if access_token and 'userinfo_endpoint' in provider_config:
        try:
            userinfo_response = requests.get(
                provider_config['userinfo_endpoint'],
                headers={'Authorization': f'Bearer {access_token}'},
                timeout=10
            )
            if userinfo_response.status_code == 200:
                additional_info = userinfo_response.json()
                user_info.update(additional_info)
        except requests.exceptions.RequestException:
            # UserInfo fetch failed, but we still have ID token claims
            pass
    
    # Store user information in the session
    session['user'] = {
        'sub': user_info.get('sub'),
        'email': user_info.get('email'),
        'email_verified': user_info.get('email_verified'),
        'name': user_info.get('name'),
        'given_name': user_info.get('given_name'),
        'family_name': user_info.get('family_name'),
        'picture': user_info.get('picture'),
        'locale': user_info.get('locale'),
        'all_claims': user_info,
    }
    
    # Store tokens in session (for API calls, token refresh, etc.)
    session['tokens'] = {
        'access_token': access_token,
        'refresh_token': refresh_token,
        'id_token': id_token,
        'token_type': tokens.get('token_type'),
        'expires_in': tokens.get('expires_in'),
    }
    
    session['authenticated'] = True
    
    # Redirect to the originally requested URL or home
    next_url = session.pop('next_url', url_for('index'))
    return redirect(next_url)


