@app.route('/logout')
def logout():
    """Log the user out by clearing the session and optionally redirecting to provider logout."""
    # Get the ID token for the logout hint
    tokens = session.get('tokens', {})
    id_token_hint = tokens.get('id_token')
    
    # Clear the session
    session.clear()
    
    # Try to redirect to the provider's end_session_endpoint if available
    try:
        provider_config = get_provider_config()
        end_session_endpoint = provider_config.get('end_session_endpoint')
        
        if end_session_endpoint:
            logout_params = {
                'post_logout_redirect_uri': request.host_url.rstrip('/'),
            }
            if id_token_hint:
                logout_params['id_token_hint'] = id_token_hint
            
            logout_url = f"{end_session_endpoint}?{urlencode(logout_params)}"
            return redirect(logout_url)
    except Exception:
        pass
    
    # If no end_session_endpoint, just redirect to home
    return redirect(url_for('index'))


